INSERT INTO public.wiki_pages (id, room_id, title, content, parent_id, created_at, updated_at) VALUES ('3b6847d9-d54d-4e67-9a06-0c70d1770fdb', 'c3497459-c4bf-4a9e-a01e-032f1a3f4df0', 'Dogma de la Ley Divina', '<p><img src="data:image/png;base64,"></p><p><br></p><p><strong><u>Orígenes Mitológicos</u></strong></p><p><br></p><p>La Legalidad representa los aspectos estructurados y disciplinados del Animæ, los principios rectores que dan forma a los caminos de individuos y sociedades por igual. Es el orden que emerge del caos, las reglas y rituales que proporcionan estabilidad y dirección en un mundo de incertidumbre. Aquellos que sostienen la Legalidad valoran la tradición y el deber, siguiendo los códigos y costumbres antiguas que han guiado a su pueblo durante generaciones.</p><p><br></p><p>En la mitología élfica, las montañas firmes y las estrellas ordenadas en el cielo son representaciones de la Legalidad. Los elfos del Dogma de la Ley Divina, conocidos como los Protectores del Orden, veneran a Legaia, la diosa de la ley y la estructura. Creen que a través de la adherencia a las leyes divinas y los rituales sagrados, se puede alcanzar la estabilidad y la prosperidad duradera.</p><p><br></p><p><strong><u>Doctrina</u></strong></p><p><br></p><p><u>Estructura</u></p><p><br></p><p>- El Dominio de la Ley Divina es una institución religiosa jerárquica con una autoridad centralizada.</p><p>- Liderada por una jerarquía de clérigos, con sacerdotes, obispos y arzobispos ocupando posiciones de autoridad.</p><p>- Estructura organizativa rígida con protocolos y procedimientos estrictos que gobiernan los ritos religiosos y la gobernanza.</p><p><br></p><p><u>Creencias y Prácticas</u></p><p><br></p><p>- Mantiene una estricta adhesión a un conjunto de leyes divinas y mandamientos, codificados en textos sagrados e interpretados por autoridades religiosas.</p><p>- Los rituales son altamente ceremoniales y regimentados, a menudo involucrando ceremonias elaboradas, sacramentos y ritos realizados por clérigos ordenados.</p><p>- Valora la tradición, la jerarquía y la disciplina, viendo la desviación del orden establecido como herejía.</p><p><br></p><p><u>Interacción con la Sociedad</u></p><p><br></p><p>- Ejerce una influencia política y social significativa, con clérigos que a menudo ocupan posiciones de poder dentro de la élite gobernante.</p><p>- Promueve la obediencia a la autoridad y la adhesión a las leyes religiosas como virtudes esenciales.</p><p>- Puede hacer cumplir la ortodoxia mediante medidas como inquisiciones, juicios por herejía y la supresión de creencias disidentes.</p>', '6a78599b-82ab-4de3-914d-76da15f88e74', '2025-08-31 15:39:56.245354', '2025-08-31 15:42:03.6');

